sql:
SELECT full_name
FROM laureates
WHERE is_alive = 0;

SELECT COUNT(*) AS total_chemistry_prizes
  FROM prizes
 WHERE category = 'Chemistry';

SELECT prize_name, MAX(award_date) AS latest_award_date
FROM prizes
WHERE prize_status = 'awarded';

external_knowledge:
- "Prized possessions" refers to the names of the prizes; 
- "Most diligent treasure hunters" refers to the top 5 users with the most distinct prizes accessed and the longest total access duration; 
- "Uncovered the most treasures" refers to accessing the most distinct prizes; 
- "Spent the most time uncovering them" refers to having the longest total access duration.

sql:
SELECT full_name
FROM laureates
ORDER BY full_name ASC;

SELECT field_of_study, COUNT(*) AS laureate_count
FROM laureates
GROUP BY field_of_study;
